// 从 supabase-js SDK 中导入创建客户端的核心函数
import { createClient } from "@supabase/supabase-js";

// 从环境变量中读取 Supabase 项目的 URL（非空断言! 确保变量存在）
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
// 从环境变量中读取 Supabase 的匿名密钥（前端可暴露的公钥）
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

// 创建并导出 Supabase 客户端实例，供整个项目复用
export const supabase = createClient(supabaseUrl, supabaseAnonKey);

// 从 next/server 模块中导入 NextResponse 类，用于构建 API 响应
import { NextResponse } from "next/server";

/**
 * 处理 GET 请求的异步函数
 * @param request - 请求对象，包含请求的所有信息（如 URL、headers、方法等）
 * @returns JSON 格式的响应
 */
export async function GET(request: Request) {
  // 使用 NextResponse.json 方法创建 JSON 响应
  return NextResponse.json({ message: "Hello from our API!" });
}

{
  "mcpServers": {  // MCP 服务器配置根节点
    "browsermcp": {  // 浏览器 MCP 服务
      "command": "npx",   // 执行命令：npx 运行 Node.js 包
      "args": [
        "-y",            // ❗ 补充：自动确认交互提示，避免首次启动卡住
        "@browsermcp/mcp@latest"  // 最新版浏览器 MCP 包
      ]
    },
    "filesystem": {  // 文件系统 MCP 服务
      "command": "npx",   // 执行命令：npx 运行 Node.js 包
      "args": [
        "-y",             // 自动确认交互提示，必加
        "@modelcontextprotocol/server-filesystem",  // 官方文件系统 MCP 包
        "/Users/username/Desktop"  // ❗ 需替换：你的实际桌面目录路径
      ]
    }
  }
}

{
  "mcpServers": {  // MCP 服务器配置根节点
    "supabase": {  // 自定义服务名称（语义化，指向 Supabase 数据库）
      "command": "npx",   // 执行命令：使用 Node.js 的 npx 工具运行包
      "args": [           // 传给 npx 的参数列表
        "-y",             // 自动确认所有交互提示（安装依赖、权限等），避免启动中断
        "@supabase/mcp-server-supabase@latest",  // Supabase 官方 MCP 包（指定最新版）
        "--read-only",    // 核心参数：限制 MCP 仅能读取 Supabase 数据，禁止写入/修改（安全）
        "--project-ref=your-project-ref"  // ❗ 修正：补充项目标识（必填，原配置为空）
      ],
      "env": {  // 环境变量（鉴权核心）
        "SUPABASE_ACCESS_TOKEN": "your-supabase-pat"  // Supabase 个人访问令牌（必填，需替换为真实值）
      }
    }
  }
}

{
  "mcpServers": {  // MCP 服务器配置根节点
    "browsermcp": {  // 自定义的服务名称（语义化，明确是浏览器 MCP 服务）
      "command": "npx",   // 执行命令：使用 Node.js 的 npx 工具运行包
      "args": [           // 传给 npx 的参数列表
        "@browsermcp/mcp@latest"  // 要运行的包名+版本：最新版的 browsermcp MCP 包
      ]
    }
  }
}

{
  "mcpServers": {  // MCP 服务器配置根节点
    "@21st-dev/magic": {  // 自定义的服务名称（直接用包名作为标识，语义清晰）
      "command": "npx",   // 执行命令：使用 Node.js 的 npx 工具运行包
      "args": [           // 传给 npx 的参数列表
        "-y",             // 自动确认所有交互式提示（如安装、权限），避免运行中断
        "@21st-dev/magic@latest",  // 要运行的包名+版本：指定最新版的 magic MCP 包
        "API_KEY=\"your-api-key\"" // 尝试传入 API 密钥参数（⚠️ 格式需注意，下文会说明）
      ]
    }
  }
}

{
  "mcpServers": {  // MCP 所有服务器配置的根节点（固定）
    "Playwright": {  // 自定义的 Playwright 服务名称（可修改，建议保持语义化）
      "command": "npx",  // 执行命令：使用 Node.js 的 npx 工具，无需全局安装包即可运行
      "args": [          // 传给 npx 的参数列表
        "-y",            // 自动确认所有交互式提示（如安装依赖、权限确认），避免运行中断
        "@executeautomation/playwright-mcp-server"  // 核心包名：Playwright 专属的 MCP 服务器包
      ],
      "env": {}  // 环境变量配置项（当前为空，可按需添加 Playwright 运行所需的环境变量）
    }
  }
}

{
  "mcpServers": {  // MCP 所有服务器配置的根节点（固定不变）
    "server-name": {  // 自定义的服务器名称（可替换，比如之前的 GitHub/time）
      "command": "executable",  // 要执行的核心程序/命令（比如 npx/python/bash 等）
      "args": ["arg1","arg2"],  // 传给 command 的参数列表（按需添加/删减）
      "env": {  // 运行命令时需要的环境变量（可选，无则可删除该字段）
        "VAR": "value"  // 环境变量名和值（可添加多个，如 "KEY1":"val1", "KEY2":"val2"）
      }
    }
  }
}

{
  "mcpServers": {  // MCP 服务器配置的总入口
    "time": {       // 名为 "time" 的时间服务配置项
      "command": "npx",  // 执行命令：使用 Node.js 的 npx 工具（无需全局安装包即可运行）
      "args": [          // 命令参数列表
        "-y",            // npx 参数：自动回答所有交互式提示为 "yes"，避免运行时卡住
        "mcp-server-time" // 要运行的包名：MCP 官方的时间服务包
      ]
    }
  }
}

{
